                            }}
                            humanTasks={humanTasks}
                            requiredSkills={requiredSkills}
                            isEditMode={isEditMode}
                            isScheduled={isScheduled}
                            isFunded={isFunded}
                            rewardIncreased={rewardIncreased}
                            topUpAmount={topUpAmount}
                            mutation={{
                                isPending: mutation.isPending,
