import type { QuestTask } from '@clawquest/shared';
import {
    createQuest,
    updateQuest,
    formatQuestResponse,
    isValidTransition,
    isQuestCreatorOrAdmin,
    isQuestOwnerOrSponsor,
    generateCollabToken,
    verifyParticipation,
    bulkVerifyParticipations,
    resolveHumanHandle,
