    // ── POST /quests/:id/participations/:pid/verify — Approve/reject proof ───
    server.post(
        '/:id/participations/:pid/verify',
        {
            schema: {
                tags: ['Quests'],
                summary: 'Verify (approve/reject) a submitted proof',
                security: [{ bearerAuth: [] }],
                params: z.object({
                    id: z.string().uuid(),
                    pid: z.string().uuid(),
